import{_ as t,c as n,o as i,a1 as s}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Erster Start: Datenverzeichnis verstehen | Antigravity Tools","description":"Lernen Sie den Speicherort des Datenverzeichnisses von Antigravity Tools und die Protokollverwaltung kennen. Meistern Sie das Öffnen des Datenverzeichnisses über die Einstellungen, das Bereinigen von Protokollen, den Taskleistenbetrieb und den automatischen Systemstart, und unterscheiden Sie die beiden Arten des automatischen Starts.","frontmatter":{"title":"Erster Start: Datenverzeichnis verstehen | Antigravity Tools","sidebarTitle":"Datenverzeichnis finden","subtitle":"Wichtig für den ersten Start: Datenverzeichnis, Protokolle, Taskleiste und automatischer Start","description":"Lernen Sie den Speicherort des Datenverzeichnisses von Antigravity Tools und die Protokollverwaltung kennen. Meistern Sie das Öffnen des Datenverzeichnisses über die Einstellungen, das Bereinigen von Protokollen, den Taskleistenbetrieb und den automatischen Systemstart, und unterscheiden Sie die beiden Arten des automatischen Starts.","tags":["Erster Start","Datenverzeichnis","Protokolle","Taskleiste","Automatischer Start"],"prerequisite":["../getting-started/","../installation/"],"order":3},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/start/first-run-data/index.md","filePath":"de/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"}'),a={name:"de/lbjlaq/Antigravity-Manager/start/first-run-data/index.md"};function r(o,e,d,l,h,c){return i(),n("div",null,[...e[0]||(e[0]=[s(`<h1 id="wichtig-fur-den-ersten-start-datenverzeichnis-protokolle-taskleiste-und-automatischer-start" tabindex="-1">Wichtig für den ersten Start: Datenverzeichnis, Protokolle, Taskleiste und automatischer Start <a class="header-anchor" href="#wichtig-fur-den-ersten-start-datenverzeichnis-protokolle-taskleiste-und-automatischer-start" aria-label="Permalink to &quot;Wichtig für den ersten Start: Datenverzeichnis, Protokolle, Taskleiste und automatischer Start&quot;">​</a></h1><p>Viele der &quot;magisch wirkenden&quot; Fähigkeiten von Antigravity Tools (Kontopool, Kontingente, Überwachung, Statistiken, Hintergrundbetrieb) basieren letztendlich auf zwei Dingen: dem <strong>Datenverzeichnis</strong> und den <strong>Protokollen</strong>. Wenn Sie diese beiden Bereiche gleich beim ersten Start verstehen, sparen Sie später viel Zeit bei der Fehlerbehebung.</p><h2 id="was-ist-das-datenverzeichnis" tabindex="-1">Was ist das Datenverzeichnis? <a class="header-anchor" href="#was-ist-das-datenverzeichnis" aria-label="Permalink to &quot;Was ist das Datenverzeichnis?&quot;">​</a></h2><p>Das <strong>Datenverzeichnis</strong> ist der Ordner, in dem Antigravity Tools den lokalen Status speichert: Konten-JSON, kontingentbezogene Dateien, Protokolldateien sowie die SQLite-Datenbanken von Token Stats/Proxy Monitor werden alle hier abgelegt. Wenn Sie Backups erstellen/migrieren/problemlösen, müssen Sie nur dieses Verzeichnis finden, um die maßgebliche Datenquelle zu finden.</p><h2 id="was-sie-nach-dieser-lektion-konnen" tabindex="-1">Was Sie nach dieser Lektion können <a class="header-anchor" href="#was-sie-nach-dieser-lektion-konnen" aria-label="Permalink to &quot;Was Sie nach dieser Lektion können&quot;">​</a></h2><ul><li>Sie wissen, wo sich das Datenverzeichnis von Antigravity Tools befindet (und können es mit einem Klick öffnen)</li><li>Sie wissen, welche Dateien gesichert werden sollten und welche Protokolle/Caches sind</li><li>Sie können bei Problemen schnell auf Protokolle und Überwachungsdatenbanken zugreifen</li><li>Sie verstehen den Unterschied zwischen &quot;Fenster schließen&quot; und &quot;Programm beenden&quot; (Taskleisten-Dienst)</li><li>Sie unterscheiden die beiden Arten des automatischen Starts: Start beim Systemstart vs. automatischer Start des Reverse-Proxys</li></ul><h2 id="ihr-aktuelles-dilemma" tabindex="-1">Ihr aktuelles Dilemma <a class="header-anchor" href="#ihr-aktuelles-dilemma" aria-label="Permalink to &quot;Ihr aktuelles Dilemma&quot;">​</a></h2><ul><li>Sie möchten Konten sichern/migrieren, wissen aber nicht, wo sie tatsächlich gespeichert sind</li><li>Die UI meldet Fehler/Reverse-Proxy-Aufrufe schlagen fehl, aber Sie finden die Protokolle nicht</li><li>Sie haben das Fenster geschlossen, gedacht, das Programm sei beendet, aber es läuft weiter im Hintergrund</li></ul><h2 id="wann-sie-diesen-ansatz-verwenden" tabindex="-1">Wann Sie diesen Ansatz verwenden <a class="header-anchor" href="#wann-sie-diesen-ansatz-verwenden" aria-label="Permalink to &quot;Wann Sie diesen Ansatz verwenden&quot;">​</a></h2><ul><li>Sie haben gerade Antigravity Tools installiert und möchten bestätigen, &quot;wo die Daten gespeichert sind&quot;</li><li>Sie möchten den Computer neu aufsetzen oder das System neu installieren und möchten zuerst Konten und Statistikdaten sichern</li><li>Sie müssen Probleme untersuchen: OAuth-Fehler, Aktualisierung von Kontingenten fehlgeschlagen, Reverse-Proxy-Start fehlgeschlagen, Aufrufe melden 401/429</li></ul><h2 id="🎒-vorbereitungen-vor-dem-start" tabindex="-1">🎒 Vorbereitungen vor dem Start <a class="header-anchor" href="#🎒-vorbereitungen-vor-dem-start" aria-label="Permalink to &quot;🎒 Vorbereitungen vor dem Start&quot;">​</a></h2><ul><li>Antigravity Tools installiert und geöffnet</li><li>Sie können auf die Settings-Seite zugreifen (Einstellungseingang oben rechts/in der Seitenleiste)</li><li>Ihr Systemkonto hat Berechtigungen für den Zugriff auf Ihr Home-Verzeichnis</li></ul><div class="warning custom-block"><p class="custom-block-title">Hinweis</p><p>Diese Lektion wird Ihnen sagen, welche Dateien &quot;echte Daten&quot; sind, aber es wird nicht empfohlen, diese Dateien manuell zu bearbeiten. Wenn Sie die Konfiguration ändern möchten, tun Sie dies vorzugsweise in der UI.</p></div><h2 id="kernkonzept" tabindex="-1">Kernkonzept <a class="header-anchor" href="#kernkonzept" aria-label="Permalink to &quot;Kernkonzept&quot;">​</a></h2><p>Merken Sie sich zuerst einen Satz:</p><p>&quot;<strong>Das Datenverzeichnis ist die einzige Quelle der Wahrheit für den lokalen Status; Protokolle sind der erste Eingang zur Fehlerbehebung.</strong>&quot;</p><p>Antigravity Tools erstellt das Datenverzeichnis <code>.antigravity_tools</code> in Ihrem Home-Verzeichnis und speichert Konten, Protokolle, Statistikdatenbanken und andere Inhalte dort (das Verzeichnis wird automatisch erstellt, wenn es nicht existiert).</p><p>Gleichzeitig wird standardmäßig die Taskleiste aktiviert: Wenn Sie das Fenster schließen, wird das Programm nicht sofort beendet, sondern in der Taskleiste ausgeblendet und im Hintergrund weiter ausgeführt.</p><h2 id="folgen-sie-mir" tabindex="-1">Folgen Sie mir <a class="header-anchor" href="#folgen-sie-mir" aria-label="Permalink to &quot;Folgen Sie mir&quot;">​</a></h2><h3 id="schritt-1-datenverzeichnis-in-den-einstellungen-offnen" tabindex="-1">Schritt 1: Datenverzeichnis in den Einstellungen öffnen <a class="header-anchor" href="#schritt-1-datenverzeichnis-in-den-einstellungen-offnen" aria-label="Permalink to &quot;Schritt 1: Datenverzeichnis in den Einstellungen öffnen&quot;">​</a></h3><p><strong>Warum</strong> Wenn Sie zuerst das Datenverzeichnis genau lokalisieren, haben Sie später einen &quot;Anknüpfungspunkt&quot; für Backups oder Fehlerbehebungen.</p><p>Öffnen Sie in Antigravity Tools Settings und wechseln Sie zu Advanced.</p><p>Sie sehen ein schreibgeschütztes Eingabefeld für &quot;Datenverzeichnis&quot; (es zeigt den tatsächlichen Pfad an) und daneben einen Öffnen-Button.</p><p>Klicken Sie auf den Öffnen-Button.</p><p><strong>Was Sie sehen sollten</strong>: Der Systemdateimanager öffnet ein Verzeichnis mit einem Pfad ähnlich wie <code>~/.antigravity_tools/</code>.</p><h3 id="schritt-2-pfad-ihres-datenverzeichnisses-bestatigen-plattformubergreifend" tabindex="-1">Schritt 2: Pfad Ihres Datenverzeichnisses bestätigen (plattformübergreifend) <a class="header-anchor" href="#schritt-2-pfad-ihres-datenverzeichnisses-bestatigen-plattformubergreifend" aria-label="Permalink to &quot;Schritt 2: Pfad Ihres Datenverzeichnisses bestätigen (plattformübergreifend)&quot;">​</a></h3><p><strong>Warum</strong> Wenn Sie später Skripte für Backups schreiben oder Probleme über die Befehlszeile untersuchen, müssen Sie den tatsächlichen Pfad dieses Verzeichnisses auf Ihrem System kennen.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-Lzrun" id="tab-cBr8BUs" checked><label data-title="macOS/Linux" for="tab-cBr8BUs">macOS/Linux</label><input type="radio" name="group-Lzrun" id="tab-iUh-G5d"><label data-title="Windows" for="tab-iUh-G5d">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">echo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$dataDir</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force $dataDir</span></span></code></pre></div></div></div><p><strong>Was Sie sehen sollten</strong>: Das Verzeichnis existiert (wenn Sie die Einstellungsseite zum ersten Mal öffnen, wird das Verzeichnis automatisch erstellt).</p><h3 id="schritt-3-schlusseldateien-im-datenverzeichnis-kennenlernen" tabindex="-1">Schritt 3: &quot;Schlüsseldateien&quot; im Datenverzeichnis kennenlernen <a class="header-anchor" href="#schritt-3-schlusseldateien-im-datenverzeichnis-kennenlernen" aria-label="Permalink to &quot;Schritt 3: &quot;Schlüsseldateien&quot; im Datenverzeichnis kennenlernen&quot;">​</a></h3><p><strong>Warum</strong> Nicht alle Dateien sind Backups wert. Unterscheiden Sie zuerst &quot;was sind Kontendaten&quot; und &quot;was sind Statistikdatenbanken/Protokolle&quot;.</p><p>Die folgenden Dateinamen stammen aus dem Projektquellcode und sind fest:</p><table tabindex="0"><thead><tr><th>Was Sie sehen</th><th>Zweck</th><th>Was Sie beachten sollten</th></tr></thead><tbody><tr><td><code>accounts.json</code></td><td>Kontenindex (enthält Kontenliste/aktuelles Konto)</td><td>Es wird empfohlen, dies beim Migrieren von Konten gemeinsam zu sichern</td></tr><tr><td><code>accounts/</code></td><td>Ein <code>*.json</code>-Pro-Datei für jedes Konto</td><td>Dies ist der Hauptteil der Kontendaten</td></tr><tr><td><code>logs/</code></td><td>Verzeichnis für Anwendungsprotokolle</td><td>Für Fehlerbehebung zuerst hier nachsehen</td></tr><tr><td><code>token_stats.db</code></td><td>SQLite-Datenbank von Token Stats</td><td>Die Daten, die Sie auf der Token Stats-Seite sehen, stammen daraus</td></tr><tr><td><code>proxy_logs.db</code></td><td>SQLite-Datenbank von Proxy Monitor</td><td>Die Anfrageprotokolle, die Sie auf der Monitor-Seite sehen, stammen daraus</td></tr><tr><td><code>warmup_history.json</code></td><td>Lokaler Verlauf von Smart Warmup</td><td>Wird hauptsächlich verwendet, um wiederholtes Warmup zu vermeiden</td></tr><tr><td><code>update_settings.json</code></td><td>Update-Check-Einstellungen (automatische Prüfung/Intervall usw.)</td><td>Normalerweise müssen Sie dies nicht manuell bearbeiten</td></tr></tbody></table><p><strong>Was Sie sehen sollten</strong>: Mindestens das <code>logs/</code>-Verzeichnis existiert; wenn Sie noch keine Konten hinzugefügt haben, sind <code>accounts.json</code>/<code>accounts/</code> möglicherweise noch nicht vorhanden.</p><h3 id="schritt-4-speicherort-der-protokolle-merken-fur-fehlerbehebung-wichtig" tabindex="-1">Schritt 4: Speicherort der Protokolle merken (für Fehlerbehebung wichtig) <a class="header-anchor" href="#schritt-4-speicherort-der-protokolle-merken-fur-fehlerbehebung-wichtig" aria-label="Permalink to &quot;Schritt 4: Speicherort der Protokolle merken (für Fehlerbehebung wichtig)&quot;">​</a></h3><p><strong>Warum</strong> Fehlermeldungen in der UI geben oft nur das &quot;Phänomen&quot; an; die tatsächliche Ursache für den Fehler (z. B. Anfragefehler, Dateilese-/schreibfehler) liegt oft in den Protokollen.</p><p>Antigravity Tools schreibt Protokolle in <code>logs/</code> im Datenverzeichnis.</p><div class="vp-code-group vp-adaptive-theme"><div class="tabs"><input type="radio" name="group-tgwCA" id="tab-rZR2xxj" checked><label data-title="macOS/Linux" for="tab-rZR2xxj">macOS/Linux</label><input type="radio" name="group-tgwCA" id="tab-LThSZl4"><label data-title="Windows" for="tab-LThSZl4">Windows</label></div><div class="blocks"><div class="language-bash vp-adaptive-theme active"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">ls</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -la</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/.antigravity_tools/logs&quot;</span></span></code></pre></div><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Get-ChildItem</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> -</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Force (</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Join-Path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> $HOME</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;.antigravity_tools\\logs&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div></div></div><p><strong>Was Sie sehen sollten</strong>: Im Verzeichnis existieren täglich rotierende Protokolldateien (Dateinamen beginnen mit <code>app.log</code>).</p><h3 id="schritt-5-wenn-sie-protokolle-bereinigen-mussen-verwenden-sie-die-ein-klick-bereinigung-auf-der-einstellungsseite" tabindex="-1">Schritt 5: Wenn Sie &quot;Protokolle bereinigen&quot; müssen, verwenden Sie die Ein-Klick-Bereinigung auf der Einstellungsseite <a class="header-anchor" href="#schritt-5-wenn-sie-protokolle-bereinigen-mussen-verwenden-sie-die-ein-klick-bereinigung-auf-der-einstellungsseite" aria-label="Permalink to &quot;Schritt 5: Wenn Sie &quot;Protokolle bereinigen&quot; müssen, verwenden Sie die Ein-Klick-Bereinigung auf der Einstellungsseite&quot;">​</a></h3><p><strong>Warum</strong> Manche Probleme möchten Sie nur einmal reproduzieren und dann das Protokoll davon separat aufbewahren; in diesem Fall ist es besser, zuerst die Protokolle zu bereinigen, um den Vergleich zu erleichtern.</p><p>Gehen Sie in Settings -&gt; Advanced, finden Sie den Protokollbereich und klicken Sie auf &quot;Protokolle bereinigen&quot;.</p><p><strong>Was Sie sehen sollten</strong>: Ein Bestätigungsdialog wird angezeigt; nach Bestätigung wird die erfolgreiche Bereinigung gemeldet.</p><div class="tip custom-block"><p class="custom-block-title">Zwei Dinge, die Sie sich Sorgen machen</p><ul><li>Protokolle werden automatisch &quot;täglich rotiert&quot; und versuchen beim Start, alte Protokolle, die älter als 7 Tage sind, zu bereinigen.</li><li>&quot;Protokolle bereinigen&quot; schneidet die Protokolldateien auf 0 Bytes ab, damit laufende Prozesse weiterhin in dieselbe Dateihandle schreiben können.</li></ul></div><h3 id="schritt-6-unterschied-zwischen-fenster-schließen-und-programm-beenden-verstehen-taskleiste" tabindex="-1">Schritt 6: Unterschied zwischen &quot;Fenster schließen&quot; und &quot;Programm beenden&quot; verstehen (Taskleiste) <a class="header-anchor" href="#schritt-6-unterschied-zwischen-fenster-schließen-und-programm-beenden-verstehen-taskleiste" aria-label="Permalink to &quot;Schritt 6: Unterschied zwischen &quot;Fenster schließen&quot; und &quot;Programm beenden&quot; verstehen (Taskleiste)&quot;">​</a></h3><p><strong>Warum</strong> Antigravity Tools aktiviert standardmäßig die Taskleiste; wenn Sie auf das Schließen-Symbol oben rechts im Fenster klicken, wird das Programm in der Taskleiste ausgeblendet und weiter ausgeführt. Wenn Sie denken, es ist beendet, entsteht leicht der Eindruck &quot;Port wird noch belegt/Läuft noch im Hintergrund&quot;.</p><p>Sie können diesen kleinen Ablauf bestätigen:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Aktion: Fenster schließen (nicht beenden)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>┌─────────────────────────────────────────────────────────────┐</span></span>
<span class="line"><span>│  Schritt 1                Schritt 2                         │</span></span>
<span class="line"><span>│  Fenster schließen   →   Suchen Sie das Symbol in der       │</span></span>
<span class="line"><span>│                          System-Taskleiste/Menüleiste      │</span></span>
<span class="line"><span>└─────────────────────────────────────────────────────────────┘</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Was Sie sehen sollten: Das Taskleistensymbol existiert noch, durch Klicken können Sie das Fenster erneut anzeigen.</span></span></code></pre></div><p>Im Taskleistenmenü gibt es auch zwei häufige Aktionen (sehr bequem ohne UI):</p><ul><li>Konto wechseln: Zum nächsten Konto wechseln</li><li>Kontingent aktualisieren: Kontingent des aktuellen Kontos aktualisieren (gleichzeitig wird das Frontend benachrichtigt, die Anzeige zu aktualisieren)</li></ul><h3 id="schritt-7-automatischen-start-beim-systemstart-einrichten-damit-es-nach-dem-start-automatisch-minimiert-wird" tabindex="-1">Schritt 7: Automatischen Start beim Systemstart einrichten (damit es nach dem Start automatisch minimiert wird) <a class="header-anchor" href="#schritt-7-automatischen-start-beim-systemstart-einrichten-damit-es-nach-dem-start-automatisch-minimiert-wird" aria-label="Permalink to &quot;Schritt 7: Automatischen Start beim Systemstart einrichten (damit es nach dem Start automatisch minimiert wird)&quot;">​</a></h3><p><strong>Warum</strong> Wenn Sie möchten, dass es wie ein &quot;Dienst&quot; arbeitet (Taskleisten-Dienst + Hintergrundaktualisierung), spart der automatische Start beim Systemstart das manuelle Öffnen jedes Mal.</p><p>Gehen Sie in Settings -&gt; General, finden Sie &quot;Automatisch beim Systemstart&quot; und wählen Sie Aktivieren.</p><p><strong>Was Sie sehen sollten</strong>: Nach dem Umschalten wird die erfolgreiche Aktivierung gemeldet; beim nächsten Start beim Systemstart wird es mit dem Parameter <code>--minimized</code> ausgeführt.</p><div class="info custom-block"><p class="custom-block-title">Zwei Arten von &quot;automatischem Start&quot;, verwechseln Sie sie nicht</p><table tabindex="0"><thead><tr><th>Name</th><th>Was bedeutet das</th><th>Beweis</th></tr></thead><tbody><tr><td>Automatischer Systemstart</td><td>Automatischer Start von Antigravity Tools nach dem Start des Computers (die Desktop-Anwendung selbst)</td><td>Startparameter enthalten <code>--minimized</code> und bieten den Befehl <code>toggle_auto_launch</code></td></tr><tr><td>Automatischer Start des Reverse-Proxys</td><td>Wenn Antigravity Tools startet und <code>proxy.auto_start=true</code> konfiguriert ist, versucht es, den lokalen Reverse-Proxy-Dienst automatisch zu starten</td><td>Liest die Konfiguration beim Anwendungsstart und führt <code>start_proxy_service(...)</code> aus</td></tr></tbody></table></div><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><ul><li>[ ] Sie können in Settings -&gt; Advanced den tatsächlichen Pfad des Datenverzeichnisses sehen</li><li>[ ] Sie können das Datenverzeichnis öffnen und <code>accounts.json</code>, <code>accounts/</code>, <code>logs/</code>, <code>token_stats.db</code>, <code>proxy_logs.db</code> grob erkennen</li><li>[ ] Sie wissen, dass sich Protokolle unter <code>logs/</code> befinden, und können sie schnell über die Befehlszeile anzeigen</li><li>[ ] Sie wissen, dass das Programm nach dem Schließen des Fensters noch in der Taskleiste läuft; zum Beenden verwenden Sie Quit im Taskleistenmenü</li><li>[ ] Sie können zwischen &quot;automatischem Systemstart&quot; und &quot;automatischem Start des Reverse-Proxys&quot; unterscheiden</li></ul><h2 id="hinweise-zu-fallstricken" tabindex="-1">Hinweise zu Fallstricken <a class="header-anchor" href="#hinweise-zu-fallstricken" aria-label="Permalink to &quot;Hinweise zu Fallstricken&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Szenario</th><th>Was Sie vielleicht tun (❌)</th><th>Empfohlene Vorgehensweise (✓)</th></tr></thead><tbody><tr><td>Datenverzeichnis nicht gefunden</td><td>Installationsverzeichnis der App im System wild durchsuchen</td><td>Gehen Sie direkt zu Settings -&gt; Advanced, sehen Sie &quot;Datenverzeichnis&quot; und öffnen Sie es mit einem Klick</td></tr><tr><td>Fenster geschlossen, aber nicht beendet</td><td>Nach dem Schließen des Fensters sofort Konfiguration ändern/Port ändern</td><td>Überprüfen Sie zuerst, ob das Taskleistensymbol noch existiert; zum Beenden verwenden Sie Quit in der Taskleiste</td></tr><tr><td>Zu viele Protokolle, schwer zu untersuchen</td><td>Während Sie das Problem reproduzieren, alte Protokolle durchsuchen</td><td>Bereinigen Sie zuerst &quot;Protokolle&quot;, reproduzieren Sie dann einmal, und sehen Sie zuletzt nur die Protokolldatei dieses Mal</td></tr><tr><td>Kontendaten ändern möchten</td><td><code>accounts/*.json</code> manuell bearbeiten</td><td>Verwenden Sie den Import/Export/Migrations-Ablauf der UI (im nächsten Abschnitt werden verwandte Kapitel behandelt)</td></tr></tbody></table><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><ul><li>Das Datenverzeichnis ist festgelegt unter <code>.antigravity_tools</code> im Home-Verzeichnis (unter macOS/Linux normalerweise ein verstecktes Verzeichnis), Konten/Protokolle/Statistikdatenbanken sind alle hier</li><li>Das Protokollverzeichnis ist <code>logs/</code>, für Fehlerbehebung zuerst hier nachsehen; bei Bedarf kann es mit einem Klick auf der Einstellungsseite bereinigt werden</li><li>Nach dem Schließen des Fensters wird es in der Taskleiste ausgeblendet und weiter ausgeführt; zum vollständigen Beenden verwenden Sie Quit in der Taskleiste</li><li>Es gibt zwei Arten des automatischen Starts: automatischer Systemstart (Anwendung) und automatischer Start des Reverse-Proxys (Proxy)</li></ul><hr><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../add-account/">Konto hinzufügen: OAuth/Refresh-Token-Doppelkanal und Best Practices</a></strong>.</p></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken, um Quellcode-Position anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>Speicherort des Datenverzeichnisses (<code>~/.antigravity_tools</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L33" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-33</td></tr><tr><td>Kontenindex und Kontendateiverzeichnis (<code>accounts.json</code> / <code>accounts/</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/account.rs#L16-L46" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/account.rs</code></a></td><td>16-46</td></tr><tr><td>Protokollverzeichnis und tägliche Rotation (<code>logs/</code> + <code>app.log</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L17-L83" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>17-83</td></tr><tr><td>Protokolle bereinigen (Datei abschneiden)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/logger.rs#L149-L169" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/logger.rs</code></a></td><td>149-169</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Taskleistenmenü und Klickereignisse (Konto wechseln/aktualisieren/anzeigen/beenden)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/tray.rs#L9-L158" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/tray.rs</code></a></td><td>9-158</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Schalter für automatischen Systemstart (<code>toggle_auto_launch</code> / <code>is_auto_launch_enabled</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/autostart.rs#L4-L39" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/autostart.rs</code></a></td><td>4-39</td></tr><tr><td>Befehle: Datenverzeichnis öffnen / Pfad abrufen / Protokolle bereinigen</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L578-L621" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>578-621</td></tr><tr><td>Datenbankdateiname von Token Stats (<code>token_stats.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/token_stats.rs#L58-L61" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/token_stats.rs</code></a></td><td>58-61</td></tr><tr><td>Datenbankdateiname von Proxy Monitor (<code>proxy_logs.db</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/proxy_db.rs#L5-L8" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/proxy_db.rs</code></a></td><td>5-8</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Aktualisierungseinstellungsdateiname (<code>update_settings.json</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/update_checker.rs#L150-L177" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/update_checker.rs</code></a></td><td>150-177</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table></details><h2 id="vorschau-auf-die-nachste-lektion-1" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion-1" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../add-account/">Konto hinzufügen: OAuth/Refresh-Token-Doppelkanal und Best Practices</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Wann Sie OAuth und wann Sie direkt refresh_token verwenden</li><li>Wie Sie mit Rückruf-Fehlern und nicht erhaltenem refresh_token umgehen</li><li>Wie Sie refresh_token stapelweise importieren, um schnell einen Kontopool zu erstellen</li></ul></blockquote>`,69)])])}const m=t(a,[["render",r]]);export{g as __pageData,m as default};
